with:
  if "language" in pred_objs:
              # Clean and optionally strip the word "language" from object names
              cleaned_langs = []
              for o in pred_objs["language"]:
                  lang = clean_obj(o)
                  # Remove trailing " language" if present (case‑insensitive)
                  if lang.lower().endswith(" language"):
                      lang = lang[: -len(" language")].strip()
                  cleaned_langs.append(lang)
              if len(cleaned_langs) == 1:
                  parts.append(f"{cleaned_langs[0]} is one of the languages of {subject}")
              else:
                  langs_str = ", ".join(cleaned_langs)
                  parts.append(f"The languages of {subject} include {langs_str}")
              handled.add("language")
